,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT i.instance_id,',
'       i.source_record_ref,',
'       i.source_module,',
'       t.template_name,',
'       i.overall_status,',
'       i.current_step_seq,',
